title CrossoverOperators's Class Diagram

package "Logic" {
  package "Operators" {
    package "CrossoverOperators" {

      enum CrossoverOperationType {
        COMPX
        MEAN
        MPX
        OPC
        TPC
        UC
        crossoverOperator
        text
      }

      abstract class CrossoverOperator {
        + generateChild()
        + isCompatible()
        + isSymmetric()
      }

      class CompositionCrossover {
        + generateChild()
        + isCompatible()
        + isSymmetric()
      }

      class MaximalPreservationCrossover {
        ~ rand : Random
        + generateChild()
        + isCompatible()
        + isSymmetric()
        + setSeed()
      }

      class OnePointCrossover {
        ~ RNG : Random
        + generateChild()
        + isCompatible()
        + isSymmetric()
        + setRandomSeed()
      }

      class UniformCrossover {
        ~ RNG : Random
        + generateChild()
        + isCompatible()
        + isSymmetric()
        + setRandomSeed()
      }

      class TwoPointCrossover {
        ~ RNG : Random
        + generateChild()
        + isCompatible()
        + isSymmetric()
        + setRandomSeed()
      }

      class OrdinalNumberMean {
        + OrdinalNumberMean()
        + generateChild()
        + isCompatible()
        + isSymmetric()
      }

      CrossoverOperationType o-- CrossoverOperator : crossoverOperator

      CompositionCrossover --|> CrossoverOperator
      MaximalPreservationCrossover --|> CrossoverOperator
      OnePointCrossover --|> CrossoverOperator
      UniformCrossover --|> CrossoverOperator
      TwoPointCrossover --|> CrossoverOperator
      OrdinalNumberMean --|> CrossoverOperator

      CompositionCrossover --> CrossoverOperator
    }
  }
}

